// Event Loop Order Explorer

console.log('start'); // 1 - synchronous

setTimeout(() => {
  console.log('timer'); // 5 - timers phase (macro-task)
}, 0);

setImmediate(() => {
  console.log('immediate'); // 6 - check phase (macro-task)
});

Promise.resolve().then(() => {
  console.log('promise'); // 4 - microtask (Promise queue)
});

process.nextTick(() => {
  console.log('nextTick'); // 3 - microtask (nextTick queue, highest priority)
});

console.log('end'); // 2 - synchronous

// Expected output:
// start
// end
// nextTick
// promise
// timer
// immediate
